st.markdown("""
<style>
header[data-testid="stHeader"] { display: none; }
#MainMenu { visibility: hidden; }
footer { visibility: hidden; }
.block-container { padding: 0 !important; max-width: 100% !important; }
.stApp { background: #070910; }
iframe { display: block; }
</style>
""", unsafe_allow_html=True)

html = "<!doctype html>\n<html>\n<head>\n<meta charset=\"utf-8\">\n<style>\n:root{\n  --bg:#070910;\n  --cell:#1b2540;\n  --cell2:#202b49;\n  --gold:#ffbe0b;\n  --goldText:#ffd166;\n  --line:#8b18d8;\n  --text:#eaf1fb;\n  --sub:#c7d2e4;\n  --markDark:#238451;\n  --markLight:#36ae70;\n  --free:#57358d;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  background:var(--bg);\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  overflow-x:hidden;\n}\n.app{\n  width:min(96vw,760px);\n  margin:0 auto;\n  padding:10px 8px 24px;\n}\n.header{text-align:center;margin:0 0 8px}\n.top-row{\n  width:min(96vw,520px);\n  margin:0 auto -2px;\n  height:28px;\n  position:relative;\n}\n.side{\n  position:absolute;\n  top:1px;\n  width:28px;height:28px;\n  display:grid;place-items:center;\n  border:1px solid rgba(255,209,102,.55);\n  background:#101522;\n  color:var(--goldText);\n  font-weight:900;\n}\n.side.left{left:14px}\n.side.right{\n  right:14px;\n  color:#b83cff;\n  border-color:rgba(184,60,255,.65);\n}\n.title{\n  color:var(--goldText);\n  font-weight:900;\n  font-size:clamp(30px,5.2vw,46px);\n  line-height:1;\n  text-shadow:0 0 8px rgba(255,209,102,.35);\n}\n.subtitle{\n  margin-top:7px;\n  color:var(--sub);\n  font-weight:900;\n  font-size:clamp(15px,2.4vw,22px);\n  letter-spacing:.08em;\n  text-transform:uppercase;\n  text-shadow:0 0 5px rgba(201,211,228,.26);\n}\n.toolbar{\n  display:flex;\n  justify-content:center;\n  align-items:center;\n  gap:4px;\n  margin:12px auto 7px;\n}\nbutton,select{\n  height:38px;\n  border:1px solid #3a2c12;\n  background:#211707;\n  color:var(--goldText);\n  font-weight:800;\n  font-size:15px;\n  padding:0 16px;\n  cursor:pointer;\n}\nbutton:hover,select:hover{filter:brightness(1.12)}\nbutton:active{filter:brightness(.9)}\nselect{padding:0 8px}\n.purple-line{\n  height:5px;\n  background:var(--line);\n  width:100%;\n  margin:0 auto 8px;\n  box-shadow:0 0 7px rgba(139,24,216,.8);\n}\n.boards{\n  display:grid;\n  justify-content:center;\n  gap:14px;\n}\n.boards.one{grid-template-columns:minmax(320px,min(94vmin,660px))}\n.boards.two,.boards.three,.boards.four{\n  grid-template-columns:repeat(2,minmax(300px,1fr));\n  width:min(96vw,980px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.board-shell{\n  border:4px solid var(--gold);\n  background:#2b210e;\n  padding:0;\n}\n.board{\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  gap:3px;\n  background:#352815;\n  aspect-ratio:1/1;\n}\n.cell{\n  position:relative;\n  border:0;\n  background:var(--cell);\n  color:var(--text);\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  text-align:center;\n  padding:6px;\n  font-weight:800;\n  font-size:clamp(10px,1.55vw,16px);\n  line-height:1.12;\n  cursor:pointer;\n  user-select:none;\n  overflow:hidden;\n  transition:filter .12s ease, transform .12s ease, background .12s ease;\n}\n.cell:nth-child(even){background:var(--cell2)}\n.cell:hover{filter:brightness(1.08)}\n.cell.free{\n  background:var(--free)!important;\n  color:#ffe27a;\n  font-weight:900;\n  font-style:italic;\n  font-size:clamp(15px,2.2vw,24px);\n  cursor:default;\n  text-shadow:0 0 5px rgba(255,226,122,.30);\n}\n.cell.free:hover{filter:none;transform:none}\n.cell.marked{\n  background:var(--markDark)!important;\n  color:#eafff3;\n}\n.cell.marked:nth-child(even){\n  background:var(--markLight)!important;\n}\n.cell.clicked{animation:clickPop .18s ease}\n.cell.marked.clicked{animation:markPop .25s ease}\n@keyframes clickPop{\n  0%{transform:scale(.96);filter:brightness(1.25)}\n  75%{transform:scale(1.035);filter:brightness(1.12)}\n  100%{transform:scale(1);filter:brightness(1)}\n}\n@keyframes markPop{\n  0%{transform:scale(.94);filter:brightness(1.32)}\n  65%{transform:scale(1.055);filter:brightness(1.16)}\n  100%{transform:scale(1);filter:brightness(1)}\n}\n.cell.rolling:not(.free){animation:rollCell .18s ease}\n@keyframes rollCell{\n  0%{filter:brightness(.78)}\n  70%{filter:brightness(1.20)}\n  100%{filter:brightness(1)}\n}\n.click-square{\n  position:fixed;\n  width:8px;height:8px;\n  background:var(--goldText);\n  pointer-events:none;\n  z-index:50;\n  animation:squarePop .46s ease-out forwards;\n}\n@keyframes squarePop{\n  from{transform:translate(0,0) scale(1);opacity:.95}\n  to{transform:translate(var(--dx),var(--dy)) scale(.35);opacity:0}\n}\n.modal-backdrop{\n  position:fixed;\n  inset:0;\n  background:rgba(0,0,0,.72);\n  display:none;\n  align-items:center;\n  justify-content:center;\n  z-index:20;\n  padding:20px;\n}\n.modal-backdrop.show{display:flex}\n.modal{\n  width:min(92vw,360px);\n  background:#111827;\n  border:2px solid var(--gold);\n  padding:16px;\n}\n.modal h2{\n  color:var(--goldText);\n  margin:0 0 10px;\n  font-size:26px;\n}\n.modal p{margin:7px 0;font-weight:700}\n.close{width:100%;margin-top:12px}\n.bingo-modal .modal{text-align:center}\n.bingo-modal h2{\n  font-size:54px;\n  color:var(--goldText);\n  text-shadow:0 0 9px var(--goldText);\n  animation:bingoPulse .7s ease-in-out infinite alternate;\n}\n@keyframes bingoPulse{\n  from{transform:scale(1)}\n  to{transform:scale(1.045);filter:brightness(1.18)}\n}\n.fall-square{\n  position:fixed;\n  top:-14px;\n  width:12px;height:12px;\n  z-index:40;\n  animation:fallSquare 1.25s linear forwards;\n}\n@keyframes fallSquare{\n  to{transform:translateY(110vh) rotate(380deg);opacity:.05}\n}\n@media(max-width:760px){\n  .boards.two,.boards.three,.boards.four{\n    grid-template-columns:1fr;\n    width:min(96vw,660px);\n  }\n  .title{font-size:30px}\n  .subtitle{font-size:15px}\n  button,select{height:34px;font-size:13px;padding:0 10px}\n}\n</style>\n</head>\n<body>\n<div class=\"app\">\n  <div class=\"header\">\n    <div class=\"top-row\">\n      <div class=\"side left\">\u25a6</div>\n      <div class=\"side right\">\u25a3</div>\n    </div>\n    <div class=\"title\">\u2726 Wings of Glory \u2726</div>\n    <div class=\"subtitle\">Low Rank Bingo</div>\n  </div>\n\n  <div class=\"toolbar\">\n    <button onclick=\"rollBoards()\">Roll</button>\n    <button onclick=\"resetMarks()\">Reset</button>\n    <button onclick=\"openRules()\">Bingo?</button>\n    <button onclick=\"toggleFull()\">Full</button>\n    <select onchange=\"setBoardCount(this.value)\">\n      <option value=\"1\">1</option>\n      <option value=\"2\">2</option>\n      <option value=\"3\">3</option>\n      <option value=\"4\">4</option>\n    </select>\n  </div>\n\n  <div class=\"purple-line\"></div>\n  <div id=\"boards\" class=\"boards one\"></div>\n</div>\n\n<div id=\"rulesModal\" class=\"modal-backdrop\" onclick=\"closeRules(event)\">\n  <div class=\"modal\">\n    <h2>Rules</h2>\n    <p>Click a square when it happens.</p>\n    <p>Free space starts marked.</p>\n    <p>5 in a row wins.</p>\n    <p>Rows, columns, diagonals count.</p>\n    <button class=\"close\" onclick=\"hideRules()\">Close</button>\n  </div>\n</div>\n\n<div id=\"bingoModal\" class=\"modal-backdrop bingo-modal\" onclick=\"hideBingo()\">\n  <div class=\"modal\">\n    <h2>BINGO!</h2>\n    <button class=\"close\" onclick=\"hideBingo()\">Close</button>\n  </div>\n</div>\n\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\nlet boards = [];\nlet marked = [];\nlet boardCount = 1;\nlet rolling = false;\n\nfunction shuffle(arr){\n  const a = [...arr];\n  for(let i=a.length-1;i>0;i--){\n    const j = Math.floor(Math.random()*(i+1));\n    [a[i],a[j]] = [a[j],a[i]];\n  }\n  return a;\n}\n\nfunction makeBoard(){\n  const shuffled = shuffle(ITEMS);\n  const board = [];\n  let idx = 0;\n  for(let i=0;i<25;i++){\n    board.push(i === 12 ? \"FREE SPACE\" : shuffled[idx++]);\n  }\n  return board;\n}\n\nfunction boardClass(){\n  if(boardCount === 1) return \"one\";\n  if(boardCount === 2) return \"two\";\n  if(boardCount === 3) return \"three\";\n  return \"four\";\n}\n\nfunction setBoardCount(n){\n  boardCount = Math.max(1, Math.min(4, Number(n)));\n  while(boards.length < boardCount){\n    boards.push(makeBoard());\n    marked.push(new Set([12]));\n  }\n  while(boards.length > boardCount){\n    boards.pop();\n    marked.pop();\n  }\n  render();\n}\n\nfunction render(){\n  const root = document.getElementById(\"boards\");\n  root.className = \"boards \" + boardClass();\n  root.innerHTML = \"\";\n  for(let b=0;b<boardCount;b++){\n    const shell = document.createElement(\"div\");\n    shell.className = \"board-shell\";\n    const board = document.createElement(\"div\");\n    board.className = \"board\";\n    for(let i=0;i<25;i++){\n      const cell = document.createElement(\"div\");\n      cell.className = \"cell\";\n      if(i === 12) cell.classList.add(\"free\");\n      if(marked[b].has(i)) cell.classList.add(\"marked\");\n      cell.textContent = boards[b][i];\n      cell.onclick = () => toggleCell(b,i);\n      board.appendChild(cell);\n    }\n    shell.appendChild(board);\n    root.appendChild(shell);\n  }\n}\n\nfunction popCell(cell){\n  cell.classList.remove(\"clicked\");\n  void cell.offsetWidth;\n  cell.classList.add(\"clicked\");\n\n  const r = cell.getBoundingClientRect();\n  const cx = r.left + r.width/2;\n  const cy = r.top + r.height/2;\n  const dirs = [[-24,-18],[24,-18],[-28,0],[28,0],[-20,20],[20,20],[0,-26],[0,26]];\n  dirs.forEach((d, idx)=>{\n    const s = document.createElement(\"div\");\n    s.className = \"click-square\";\n    s.style.left = cx + \"px\";\n    s.style.top = cy + \"px\";\n    s.style.setProperty(\"--dx\", d[0] + \"px\");\n    s.style.setProperty(\"--dy\", d[1] + \"px\");\n    s.style.background = idx % 2 ? \"#ffd166\" : \"#ffbe0b\";\n    document.body.appendChild(s);\n    setTimeout(()=>s.remove(), 520);\n  });\n}\n\nfunction toggleCell(b,i){\n  if(i === 12 || rolling) return;\n  const boardEl = document.getElementById(\"boards\").children[b].querySelector(\".board\");\n  const cell = boardEl.children[i];\n\n  if(marked[b].has(i)){\n    marked[b].delete(i);\n    cell.classList.remove(\"marked\");\n  }else{\n    marked[b].add(i);\n    cell.classList.add(\"marked\");\n  }\n\n  popCell(cell);\n  if(hasBingo(marked[b])) showBingo();\n}\n\nfunction winLines(){\n  const lines = [];\n  for(let r=0;r<5;r++) lines.push([0,1,2,3,4].map(c=>r*5+c));\n  for(let c=0;c<5;c++) lines.push([0,1,2,3,4].map(r=>r*5+c));\n  lines.push([0,6,12,18,24]);\n  lines.push([4,8,12,16,20]);\n  return lines;\n}\n\nfunction hasBingo(set){\n  return winLines().some(line => line.every(i => set.has(i)));\n}\n\nfunction rollBoards(){\n  if(rolling) return;\n  rolling = true;\n  const cells = () => Array.from(document.querySelectorAll(\".cell:not(.free)\"));\n  let steps = 8;\n\n  function spin(step){\n    const temp = Array.from({length:boardCount}, () => makeBoard());\n\n    cells().forEach((cell,idx)=>{\n      const boardIndex = Math.floor(idx/24);\n      const innerIndex = idx % 24;\n      const pool = temp[boardIndex].filter((_,i)=>i!==12);\n      cell.textContent = pool[innerIndex] || ITEMS[Math.floor(Math.random()*ITEMS.length)];\n      cell.classList.remove(\"marked\");\n      cell.classList.remove(\"rolling\");\n      void cell.offsetWidth;\n      cell.classList.add(\"rolling\");\n    });\n\n    if(step < steps){\n      setTimeout(()=>spin(step+1), 65 + step*13);\n    }else{\n      boards = Array.from({length:boardCount}, () => makeBoard());\n      marked = Array.from({length:boardCount}, () => new Set([12]));\n      rolling = false;\n      render();\n    }\n  }\n\n  spin(0);\n}\n\nfunction resetMarks(){\n  marked = Array.from({length:boardCount}, () => new Set([12]));\n  render();\n}\n\nfunction openRules(){ document.getElementById(\"rulesModal\").classList.add(\"show\"); }\nfunction hideRules(){ document.getElementById(\"rulesModal\").classList.remove(\"show\"); }\nfunction closeRules(e){ if(e.target.id === \"rulesModal\") hideRules(); }\nfunction showBingo(){\n  document.getElementById(\"bingoModal\").classList.add(\"show\");\n  bingoSquares();\n}\nfunction hideBingo(){ document.getElementById(\"bingoModal\").classList.remove(\"show\"); }\n\nfunction bingoSquares(){\n  const colors = [\"#ffd166\",\"#ffbe0b\",\"#258f55\",\"#3db875\",\"#5b3a93\"];\n  for(let i=0;i<34;i++){\n    const s = document.createElement(\"div\");\n    s.className = \"fall-square\";\n    s.style.left = (Math.random()*100) + \"vw\";\n    s.style.background = colors[Math.floor(Math.random()*colors.length)];\n    s.style.animationDelay = (Math.random()*0.2) + \"s\";\n    document.body.appendChild(s);\n    setTimeout(()=>s.remove(), 1500);\n  }\n}\n\nfunction toggleFull(){\n  try{\n    if(document.fullscreenElement){\n      document.exitFullscreen();\n    }else{\n      document.documentElement.requestFullscreen();\n    }\n  }catch(e){}\n}\n\ndocument.addEventListener(\"keydown\", e=>{\n  if(e.key === \"Escape\"){\n    hideRules();\n    hideBingo();\n  }\n});\n\nboards = [makeBoard()];\nmarked = [new Set([12])];\nrender();\n</script>\n</body>\n</html>\n"

components.html(html, height=920, scrolling=True)
